import React from 'react';
import { useDispatch, useSelector } from 'react-redux';

const Posts = () => {
    const dispatch = useDispatch();
    const [data, loading, error] = useSelector(state => state.posts);

    return (
        <div>
            <h1>Posts</h1>
        </div>
    );
}

export default Posts;
